+    #[test]
+    fn await_point_debug_clone_eq_hash() {
+        use std::collections::HashSet;
+
+        let p1 = AwaitPoint::anonymous(5);
+        let p2 = p1.clone();
+        assert_eq!(p1, p2);
+
+        let p3 = AwaitPoint::anonymous(6);
+        assert_ne!(p1, p3);
+
+        let mut set = HashSet::new();
+        set.insert(p1.clone());
+        set.insert(p2);
+        assert_eq!(set.len(), 1);
+        set.insert(p3);
+        assert_eq!(set.len(), 2);
+
+        let dbg = format!("{:?}", p1);
+        assert!(dbg.contains("AwaitPoint"));
+    }
