+    #[test]
+    fn monotonicity_debug_clone_copy_eq_hash() {
+        use std::collections::HashSet;
+
+        let m = Monotonicity::Monotone;
+        let m2 = m; // Copy
+        let m3 = m.clone();
+        assert_eq!(m, m2);
+        assert_eq!(m2, m3);
+
+        let nm = Monotonicity::NonMonotone;
+        assert_ne!(m, nm);
+
+        let mut set = HashSet::new();
+        set.insert(m);
+        set.insert(m2);
+        assert_eq!(set.len(), 1);
+        set.insert(nm);
+        assert_eq!(set.len(), 2);
+
+        let dbg = format!("{m:?}");
+        assert!(dbg.contains("Monotone"));
+    }
+
